def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap == 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2:
            base = ratio ** 3
            log_term = np.log(ratio + 1e-9)
            exp_term = np.exp(-ratio)
            priorities[i] = base + log_term + exp_term
        elif 1 < ratio <= 2:
            val = 0
            for k in range(1, 6):
                val += (ratio - 1) ** k / (k * np.math.factorial(k))
            priorities[i] = val * 10
        elif 0.3 < ratio <= 1:
            sum_log = 0
            count = 0
            for j in range(1, 8):
                val = ratio + j * 0.07
                if val < 1:
                    sum_log += np.log(1 - val + 1e-9)
                    count += 1
            if count == 0:
                priorities[i] = 1 / (1 - ratio + 1e-9)
            else:
                priorities[i] = -sum_log / count + (1 - ratio) * 5
        else:
            prod = 1
            for m in range(1, 5):
                term = 1 - (ratio + m * 0.05)
                if term > 0:
                    prod *= term
                else:
                    prod *= 1e-3
            priorities[i] = 1 / (prod + 1e-9) + ratio * 20
        if priorities[i] < 0:
            priorities[i] = 0
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 1
    for i in range(len(priorities)):
        if np.isinf(priorities[i]) or priorities[i] > max_priority * 10:
            priorities[i] = max_priority * 10
    return priorities
